     1→const express = require('express');
     2→const Anthropic = require('@anthropic-ai/sdk');
     3→const rateLimit = require('express-rate-limit');
     4→const { verifyToken } = require('../middleware/firebaseAuth');
     5→
     6→const router = express.Router();
     7→
     8→const client = new Anthropic({
     9→  apiKey: process.env.ANTHROPIC_API_KEY,
    10→});
    11→
    12→// Rate limiter: 60 requests per 15 minutes per IP
    13→const aiLimiter = rateLimit({
    14→  windowMs: 15 * 60 * 1000,
    15→  max: 60,
    16→  message: { error: 'Too many requests, please try again later.' },
    17→  standardHeaders: true,
    18→  legacyHeaders: false,
    19→});
    20→
    21→// Category/tool definitions (mirrors frontend data/categories.js — system prompts and builders)
    22→// We re-import these here so backend is the source of truth for prompts
    23→const CATEGORY_PROMPTS = require('./categoryPrompts');
    24→
    25→// POST /api/ai/generate  — streaming SSE response
    26→router.post('/generate', aiLimiter, verifyToken, async (req, res) => {
    27→  const { categoryId, toolId, inputs } = req.body;
    28→
    29→  if (!categoryId || !toolId || !inputs) {
    30→    return res.status(400).json({ error: 'Missing required fields: categoryId, toolId, inputs' });
    31→  }
    32→
    33→  // Look up the tool config
    34→  const tool = CATEGORY_PROMPTS[categoryId]?.[toolId];
    35→  if (!tool) {
    36→    return res.status(404).json({ error: `Tool "${toolId}" not found in category "${categoryId}"` });
    37→  }
    38→
    39→  // Plan-based access control (read from Firestore for accuracy)
    40→  const PLAN_ACCESS = {
    41→    free:      { allowedTools: ['marketing:seo-keyword-research', 'marketing:seo-meta-tags', 'marketing:instagram-audit'] },
    42→    grow:      { categories: ['marketing', 'content', 'digital'], allowedTools: ['strategy:business-plan'] },
    43→    scale:     { categories: ['marketing', 'content', 'digital', 'ecommerce', 'agency', 'creative'], allowedTools: ['strategy:business-plan'] },
    44→    evolution: { categories: ['marketing', 'content', 'digital', 'ecommerce', 'agency', 'creative', 'finance', 'startup', 'strategy'], allowedTools: [] },
    45→    admin:     { allAccess: true },
    46→  };
    47→  // Backward compat: map legacy plan names to current ones
    48→  const PLAN_ALIASES = { 'pro': 'grow', 'business': 'evolution' };
    49→  const TRIAL_DAYS = 14;
    50→
    51→  // Admin UID override — checked FIRST, bypasses Firestore entirely
    52→  const adminUids = (process.env.ADMIN_UIDS || '').split(',').map(s => s.trim()).filter(Boolean);
    53→  const isAdminUid = adminUids.includes(req.user?.uid);
    54→
    55→  let userSubscription = req.user?.subscription || 'free';
    56→  let userCreatedAt = null;
    57→
    58→  if (!isAdminUid) {
    59→    try {
    60→      const adminSdk = require('firebase-admin');
    61→      if (adminSdk.apps.length > 0) {
    62→        const fsDb = adminSdk.firestore();
    63→        const userDoc = await fsDb.collection('users').doc(req.user.uid).get();
    64→        if (userDoc.exists) {
    65→          const data = userDoc.data();
    66→          userSubscription = data.subscription || 'free';
    67→          userCreatedAt = data.createdAt?.toMillis?.() || null;
    68→        }
    69→      }
    70→    } catch (err) {
    71→      console.error('[Subscription] Firestore read failed for uid', req.user?.uid, ':', err.message);
    72→    }
    73→    // Normalize legacy plan names
    74→    userSubscription = PLAN_ALIASES[userSubscription] || userSubscription;
    75→  } else {
    76→    userSubscription = 'admin';
    77→  }
    78→
    79→  console.log('[Access]', { uid: req.user?.uid, subscription: userSubscription, tool: `${categoryId}:${toolId}`, isAdminUid });
    80→
    81→  const plan = PLAN_ACCESS[userSubscription] || PLAN_ACCESS.free;
    82→
    83→  // Check trial: free users within 14 days get full access
    84→  const inTrial = userSubscription === 'free'
    85→    && userCreatedAt !== null
    86→    && (Date.now() - userCreatedAt) < TRIAL_DAYS * 24 * 60 * 60 * 1000;
    87→
    88→  const toolKey = `${categoryId}:${toolId}`;
    89→  const hasAccess = plan.allAccess
    90→    || inTrial
    91→    || plan.categories?.includes(categoryId)
    92→    || plan.allowedTools?.includes(toolKey);
    93→
    94→  if (!hasAccess) {
    95→    return res.status(403).json({
    96→      error: 'This tool is not available on your current plan. Upgrade to access it.',
    97→      upgradeRequired: true,
    98→    });
    99→  }
   100→
   101→  // Language instruction based on user preference
   102→  const LANGUAGE_NAMES = { en: 'English', es: 'Spanish', fr: 'French', de: 'German', it: 'Italian' };
   103→  const lang = inputs._language && LANGUAGE_NAMES[inputs._language] ? inputs._language : 'en';
   104→  const languageInstruction = lang !== 'en'
   105→    ? `\n\nIMPORTANT: You MUST respond entirely in ${LANGUAGE_NAMES[lang]}. All section titles, content, analysis, tables and text must be written in ${LANGUAGE_NAMES[lang]}.`
   106→    : '';
   107→
   108→  const systemPrompt = tool.systemPrompt + languageInstruction;
   109→  const baseUserMessage = tool.buildUserMessage(inputs);
   110→
   111→  // Append business context fields if provided (injected for all non-creative categories)
   112→  const bizLines = [];
   113→  if (inputs._website_url) bizLines.push(`Business Website: ${inputs._website_url}`);
   114→  if (inputs._location)    bizLines.push(`Business Location: ${inputs._location}`);
   115→  const userMessage = bizLines.length > 0
   116→    ? `${baseUserMessage}\n\n**Business Context:**\n${bizLines.join('\n')}`
   117→    : baseUserMessage;
   118→
   119→  // Set SSE headers
   120→  res.setHeader('Content-Type', 'text/event-stream');
   121→  res.setHeader('Cache-Control', 'no-cache');
   122→  res.setHeader('Connection', 'keep-alive');
   123→  res.setHeader('X-Accel-Buffering', 'no');
   124→  res.flushHeaders();
   125→
   126→  try {
   127→    const stream = client.messages.stream({
   128→      model: tool.model || 'claude-sonnet-4-6',
   129→      max_tokens: tool.maxTokens || 4096,
   130→      system: systemPrompt,
   131→      messages: [{ role: 'user', content: userMessage }],
   132→    });
   133→
   134→    stream.on('text', (text) => {
   135→      res.write(`data: ${JSON.stringify({ text })}\n\n`);
   136→    });
   137→
   138→    stream.on('error', (err) => {
   139→      console.error('[AI Stream Error]', err.message);
   140→      res.write(`data: ${JSON.stringify({ error: 'AI generation error' })}\n\n`);
   141→      res.end();
   142→    });
   143→
   144→    stream.on('end', () => {
   145→      res.write('data: [DONE]\n\n');
   146→      res.end();
   147→    });
   148→
   149→    // Handle client disconnect
   150→    req.on('close', () => {
   151→      stream.abort();
   152→    });
   153→  } catch (err) {
   154→    console.error('[AI Route Error]', err.message);
   155→    if (!res.headersSent) {
   156→      return res.status(500).json({ error: 'Failed to generate AI response' });
   157→    }
   158→    res.write(`data: ${JSON.stringify({ error: err.message })}\n\n`);
   159→    res.end();
   160→  }
   161→});
   162→
   163→module.exports = router;
   164→

