    60→    await createUserProfile(result.user);
    61→    return result;
    62→  }
    63→
    64→  async function logout() {
    65→    setUserProfile(null);
    66→    return signOut(auth);
    67→  }
    68→
    69→  async function resetPassword(email) {
    70→    return sendPasswordResetEmail(auth, email);
    71→  }
    72→
    73→  async function refreshUserProfile(uid) {
    74→    const userRef = doc(db, 'users', uid || currentUser?.uid);
    75→    const snap = await getDoc(userRef);
    76→    if (snap.exists()) {
    77→      setUserProfile(snap.data());
    78→      return snap.data();
    79→    }
    80→    return null;
    81→  }
    82→
    83→  useEffect(() => {
    84→    const unsubscribe = onAuthStateChanged(auth, async (user) => {
    85→      setCurrentUser(user);
    86→      if (user) {
    87→        await createUserProfile(user);
    88→      } else {
    89→        setUserProfile(null);
    90→      }
    91→      setLoading(false);
    92→    });
    93→    return unsubscribe;
    94→  }, []);
    95→
    96→  const value = {
    97→    currentUser,
    98→    userProfile,
    99→    loading,
   100→    register,
   101→    login,
   102→    logout,
   103→    signInWithGoogle,
   104→    resetPassword,
   105→    refreshUserProfile,
   106→  };
   107→
   108→  return (
   109→    <AuthContext.Provider value={value}>
   110→      {!loading && children}
   111→    </AuthContext.Provider>
   112→  );
   113→}
