     8→// Lazy init — avoids crashing the server at startup if OPENAI_API_KEY is not yet set
     9→let openai = null;
    10→function getOpenAI() {
    11→  if (!openai) {
    12→    if (!process.env.OPENAI_API_KEY) {
    13→      throw new Error('OPENAI_API_KEY is not configured on the server.');
    14→    }
