    16→  }
    17→  return openai;
    18→}
    19→
    20→// 10 images per hour per IP
    21→const imageLimiter = rateLimit({
    22→  windowMs: 60 * 60 * 1000,
    23→  max: 10,
    24→  message: { error: 'Image generation limit reached. Try again in an hour.' },
    25→  standardHeaders: true,
    26→  legacyHeaders: false,
    27→});
    28→
    29→// POST /api/image/generate-logo
    30→router.post('/generate-logo', imageLimiter, verifyToken, async (req, res) => {
    31→  const { inputs } = req.body;
    32→
    33→  if (!inputs?.brand_name || !inputs?.style) {
    34→    return res.status(400).json({ error: 'Missing required fields: brand_name, style' });
    35→  }
    36→
    37→  const colorNote = inputs.colors ? `, using colors: ${inputs.colors}` : '';
    38→  const valuesNote = inputs.values ? `, conveying: ${inputs.values}` : '';
    39→
    40→  const prompt = `A professional, minimalist logo for "${inputs.brand_name}", a ${inputs.industry || 'business'} brand. Style: ${inputs.style}${colorNote}${valuesNote}. Clean vector-style logo isolated on a pure white background. No background gradients. High quality, scalable, suitable for business cards, websites and app icons.`;
    41→
    42→  try {
    43→    const response = await getOpenAI().images.generate({
    44→      model: 'dall-e-3',
