    80→  const moodNote = inputs.mood ? `, mood: ${inputs.mood}` : '';
    81→  const lightingNote = inputs.lighting ? `, lighting: ${inputs.lighting}` : '';
    82→  const colorNote = inputs.colors ? `, color palette: ${inputs.colors}` : '';
    83→  const negativeHint = inputs.negative ? ` Avoid: ${inputs.negative}.` : '';
    84→
